import React, { useRef, useState } from "react";
import "./Upload.css";

export default function MultiUpload() {
  const fileInputRef = useRef(null);
  const [files, setFiles] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [dragging, setDragging] = useState(false);

  const handleClick = () => fileInputRef.current.click();

  const handleFiles = (newFiles) => {
    const valid = Array.from(newFiles).filter(file =>
      file.name.match(/\.(pdf|docx|txt)$/)
    );

    setFiles(prev => {
      const existing = prev.map(f => f.name);
      return [...prev, ...valid.filter(f => !existing.includes(f.name))];
    });
  };

  const uploadAll = async () => {
    if (files.length === 0) return;
    setUploading(true);

    await Promise.all(
      files.map(file => {
        const formData = new FormData();
        formData.append("file", file);

        return fetch("http://localhost:8001/upload", {
          method: "POST",
          body: formData
        });
      })
    );

    setFiles([]);
    setUploading(false);
  };

  return (
    <div
      className={`upload-wrapper ${dragging ? "dragging" : ""}`}
      onDrop={(e) => {
        e.preventDefault();
        setDragging(false);
        handleFiles(e.dataTransfer.files);
      }}
      onDragOver={(e) => {
        e.preventDefault();
        setDragging(true);
      }}
      onDragLeave={() => setDragging(false)}
    >
      <button className="upload-btn" onClick={handleClick}>📎</button>

      <input
        type="file"
        multiple
        ref={fileInputRef}
        hidden
        accept=".pdf,.docx,.txt"
        onChange={(e) => handleFiles(e.target.files)}
      />

      <span className="hint">Drop files or click</span>

      <button className="upload-all-btn" onClick={uploadAll}>
        {uploading ? "Uploading..." : "Upload"}
      </button>

      <div className="file-list">
        {files.map((f, i) => (
          <div key={i} className="file-chip">
            {f.name}
          </div>
        ))}
      </div>
    </div>
  );
}
